#include "gemm_add_relu_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

// UB budget estimation: For matmul, we need double buffers for A, B, C, and workspace.
// Conservative:  A tile: tileM*tileK, B tile: tileK*tileN, C tile: tileM*tileN (all floats)
// plus workspace for cube. Total floats ~ tileM*tileK + tileK*tileN + tileM*tileN + extra.
// We use a simple heuristic: max tile size such that total bytes < UB_BUDGET_BYTES
static constexpr uint32_t UB_BUDGET_BYTES = 128 * 1024;  // 128KB per core
static constexpr uint32_t ALIGN_UNIT = 16;               // matmul alignment

static uint32_t AlignUp(uint32_t x, uint32_t a) { return ((x + a - 1) / a) * a; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    GemmAddReluCustomTilingData tiling;

    // Get shapes: x shape [batch, in_feat], w shape [out_feat, in_feat], bias shape [out_feat]
    auto x_shape = context->GetInputShape(0)->GetOriginShape();
    auto w_shape = context->GetInputShape(1)->GetOriginShape();
    auto bias_shape = context->GetInputShape(2)->GetOriginShape();

    uint32_t M = static_cast<uint32_t>(x_shape.GetDim(0));
    uint32_t K = static_cast<uint32_t>(x_shape.GetDim(1));
    uint32_t N = static_cast<uint32_t>(w_shape.GetDim(0));
    // verify K matches w's second dim
    // bias is N

    // Determine tile sizes based on UB budget
    // We'll pick tileM and tileN as powers of two that fit, tileK as a fraction
    uint32_t tileM = 128;   // adjust
    uint32_t tileN = 128;
    uint32_t tileK = 256;   // adjust

    // Ensure alignment
    tileM = AlignUp(tileM, ALIGN_UNIT);
    tileN = AlignUp(tileN, ALIGN_UNIT);
    tileK = AlignUp(tileK, ALIGN_UNIT);

    // Clamp to problem sizes
    if (tileM > M) tileM = M;
    if (tileN > N) tileN = N;
    if (tileK > K) tileK = K;

    // Simple blockDim: use number of M tiles
    uint32_t numTilesM = (M + tileM - 1) / tileM;
    uint32_t blockDim = numTilesM;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_N(N);
    tiling.set_K(K);
    tiling.set_tileM(tileM);
    tiling.set_tileN(tileN);
    tiling.set_tileK(tileK);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

